/**
 * Generate market test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateMarketTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateMarketTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateMarketTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<MarketCreateRequest> = {}
): MarketCreateRequest {
  let baseData: MarketCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalMarketFixture };
      break;

    case 'complete':
      baseData = { ...completeMarketFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidMarketFixture } as MarketCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueMarketFixture,
        title: `Test Market ${generateUniqueId()}`,
      };
      break;

    default:
      baseData = { ...completeMarketFixture };
  }

  return { ...baseData, ...overrides };
}

